code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            double sum = 0;
            for (int i = 1; i <= N; i++) {
                sum += 1.0 / i;
            }
            System.out.printf("%.1f\n", N * sum);
        }
    }
}

